export function getRegrasGeraisPrompt() {
  return `
  1. A REGRA PRINCIPAL: A IA deve ler a conversa e identificar QUAL foi a principal ação/dúvida abordada, e então escolher a Tag de "Área" e de "Tipo" que melhor descreve isso baseada no dicionário oficial.
  2. DEVOLUÇÃO DO FORMATO: Sempre devolva o JSON estritamente formatado com os campos "protocolo", "tag_area" e "tag_tipo".
  3. ADICIONAIS: Se a tag AREA escolhida exigir o tipo "Adicionais" segundo o dicionário, você deve OBRIGATORIAMENTE usar o tipo "Adicionais".
  4. INSTRUÇÃO vs APRESENTAÇÃO: Se o agente mandou o passo a passo de como fazer, é Instrução. Se ele só disse que a ferramenta existe, é Apresentação.
  `;
}

export function getDicionarioParaIA() {
  let dicionarioStr = "--- TIPOS PERMITIDOS ---\n";
  for (const [tipo, desc] of Object.entries(LUMA_TAGS.TIPOS)) {
    dicionarioStr += `- "${tipo}": ${desc}\n`;
  }

  dicionarioStr += "\n--- ÁREAS PERMITIDAS ---\n";
  for (const [area, desc] of Object.entries(LUMA_TAGS.AREAS)) {
    dicionarioStr += `- "${area}": ${desc}\n`;
  }
  
  return dicionarioStr;
}